'use client'
import { cn, useSignalEffect, useSignals } from '@cascivo/core'
import { useRef, type CSSProperties, type HTMLAttributes, type ReactNode } from 'react'
import styles from './scroll-area.module.css'

export interface ScrollAreaProps extends HTMLAttributes<HTMLDivElement> {
  /** Max block size of the scroll container (any CSS length). */
  height?: string
  /** Max inline size of the scroll container (any CSS length). */
  width?: string
  /** Which axes may scroll. */
  orientation?: 'vertical' | 'horizontal' | 'both'
  /** Edge affordance: box-shadow (default), a mask-image fade (HeroUI ScrollShadow), or none. */
  edges?: 'shadow' | 'mask' | 'none'
  children?: ReactNode
}

export function ScrollArea({
  height,
  width,
  orientation = 'vertical',
  edges = 'shadow',
  className,
  style,
  children,
  ...props
}: ScrollAreaProps) {
  useSignals()
  const nodeRef = useRef<HTMLDivElement | null>(null)

  // Drive scroll-shadow data attributes from the scroll position. No useEffect —
  // useSignalEffect runs the subscription once on mount and cleans up on unmount.
  useSignalEffect(() => {
    const node = nodeRef.current
    if (!node) return

    const update = (): void => {
      const atTop = node.scrollTop <= 0
      const atBottom = node.scrollTop + node.clientHeight >= node.scrollHeight - 1
      const atStart = node.scrollLeft <= 0
      const atEnd = node.scrollLeft + node.clientWidth >= node.scrollWidth - 1
      node.toggleAttribute('data-scroll-top', !atTop)
      node.toggleAttribute('data-scroll-bottom', !atBottom)
      node.toggleAttribute('data-scroll-start', !atStart)
      node.toggleAttribute('data-scroll-end', !atEnd)
    }

    update()
    node.addEventListener('scroll', update, { passive: true })
    return () => {
      node.removeEventListener('scroll', update)
    }
  })

  const sizeStyle = {
    ...(height !== undefined ? { '--cascivo-scroll-area-height': height } : {}),
    ...(width !== undefined ? { '--cascivo-scroll-area-width': width } : {}),
    ...style,
  } as CSSProperties

  return (
    <div
      ref={nodeRef}
      data-orientation={orientation}
      data-edges={edges}
      className={cn(styles['root'], className)}
      style={sizeStyle}
      {...props}
    >
      {children}
    </div>
  )
}

@layer cascivo.component {
  .root {
    max-block-size: var(--cascivo-scroll-area-height, none);
    max-inline-size: var(--cascivo-scroll-area-width, none);
    scrollbar-width: thin;
    scrollbar-color: var(--cascivo-color-border) transparent;

    &[data-orientation='vertical'] {
      overflow-x: hidden;
      overflow-y: auto;
    }

    &[data-orientation='horizontal'] {
      overflow-x: auto;
      overflow-y: hidden;
    }

    &[data-orientation='both'] {
      overflow: auto;
    }

    &::-webkit-scrollbar {
      inline-size: 0.5rem;
      block-size: 0.5rem;
    }

    &::-webkit-scrollbar-track {
      background: transparent;
    }

    &::-webkit-scrollbar-thumb {
      background-color: var(--cascivo-color-border);
      border-radius: var(--cascivo-radius-control);
    }

    &::-webkit-scrollbar-thumb:hover {
      background-color: var(--cascivo-color-text-subtle);
    }

    /* Scroll shadows — gradients appear only when content overflows in that direction. */
    background:
      linear-gradient(var(--cascivo-color-surface) 30%, transparent) center top / 100% 1.5rem
        no-repeat,
      linear-gradient(transparent, var(--cascivo-color-surface) 70%) center bottom / 100% 1.5rem
        no-repeat;
    background-attachment: local, local;

    &[data-scroll-top]:not([data-edges='none']) {
      box-shadow: inset 0 0.5rem 0.4rem -0.4rem
        color-mix(in srgb, var(--cascivo-color-text) 12%, transparent);
    }

    &[data-scroll-bottom]:not([data-edges='none']) {
      box-shadow: inset 0 -0.5rem 0.4rem -0.4rem
        color-mix(in srgb, var(--cascivo-color-text) 12%, transparent);
    }

    &[data-scroll-top][data-scroll-bottom]:not([data-edges='none']) {
      box-shadow:
        inset 0 0.5rem 0.4rem -0.4rem color-mix(in srgb, var(--cascivo-color-text) 12%, transparent),
        inset 0 -0.5rem 0.4rem -0.4rem
          color-mix(in srgb, var(--cascivo-color-text) 12%, transparent);
    }

    /* ScrollShadow fade (HeroUI parity): box-shadow above is the static fallback;
       the mask-image gradient progressively replaces it on the same overflow edges. */
    &[data-edges='mask'][data-scroll-top] {
      mask-image: linear-gradient(to bottom, transparent, black 1.5rem);
    }
    &[data-edges='mask'][data-scroll-bottom] {
      mask-image: linear-gradient(to top, transparent, black 1.5rem);
    }
    &[data-edges='mask'][data-scroll-top][data-scroll-bottom] {
      mask-image: linear-gradient(
        to bottom,
        transparent,
        black 1.5rem,
        black calc(100% - 1.5rem),
        transparent
      );
    }
  }
}
